	private calculateChips(bet: number): number[] {
		const vals = [500, 100, 25, 10, 5, 1];
		const counts: number[] = [];
		let remaining = bet;
		for (const v of vals) {
			const count = Math.min(5, Math.floor(remaining / v));
			counts.push(count);
			remaining -= count * v;
		}
		return counts;
	}

